return [
  { json: { url: 'https://news.google.com/rss/search?q=cameroon&hl=en-US&gl=US&ceid=US:en', source_name: 'google_news_en', language: 'en' } },
  { json: { url: 'https://news.google.com/rss/search?q=cameroun&hl=fr-FR&gl=FR&ceid=FR:fr', source_name: 'google_news_fr', language: 'fr' } },
  { json: { url: 'https://www.journalducameroun.com/feed/', source_name: 'journal_du_cameroun', language: 'fr' } },
  { json: { url: 'https://www.camer.be/rss.php', source_name: 'camer_be', language: 'fr' } },
  { json: { url: 'https://www.mutations.cm/feed/', source_name: 'mutations_cm', language: 'fr' } },
  { json: { url: 'https://www.rfi.fr/fr/afrique/cameroun/rss', source_name: 'rfi_afrique', language: 'fr' } }
];

const sources = $('Set RSS Sources').all();
return $input.all().map((item, i) => ({
  json: {
    source_name: sources[i].json.source_name,
    language: sources[i].json.language,
    xmlData: item.json.data || ''
  }
}));

const crypto = require('crypto');

const items = $input.all();
const rows = [];

function getTagContent(block, tag) {
  const cdataOpen = '<' + tag + '><![CDATA[';
  const cdataClose = ']]></' + tag + '>';
  let si = block.indexOf(cdataOpen);
  if (si !== -1) {
    const ei = block.indexOf(cdataClose, si);
    if (ei !== -1) return block.slice(si + cdataOpen.length, ei).trim();
  }
  const open = '<' + tag + '>';
  const close = '</' + tag + '>';
  si = block.indexOf(open);
  if (si !== -1) {
    const ei = block.indexOf(close, si);
    if (ei !== -1) return block.slice(si + open.length, ei).trim();
  }
  return '';
}

function getAttrValue(block, attr) {
  const DQ = String.fromCharCode(34);
  const SQ = String.fromCharCode(39);
  const dqSearch = attr + '=' + DQ;
  let si = block.indexOf(dqSearch);
  if (si !== -1) {
    const start = si + dqSearch.length;
    const end = block.indexOf(DQ, start);
    if (end !== -1) return block.slice(start, end);
  }
  const sqSearch = attr + '=' + SQ;
  si = block.indexOf(sqSearch);
  if (si !== -1) {
    const start = si + sqSearch.length;
    const end = block.indexOf(SQ, start);
    if (end !== -1) return block.slice(start, end);
  }
  return '';
}

function getImageUrl(block) {
  const tags = ['<media:content ', '<enclosure '];
  for (const tag of tags) {
    const idx = block.indexOf(tag);
    if (idx !== -1) {
      const end = block.indexOf('>', idx);
      if (end === -1) continue;
      const tagContent = block.slice(idx, end);
      const url = getAttrValue(tagContent, 'url');
      if (url) return url;
    }
  }
  return null;
}

for (const item of items) {
  const source_name = item.json.source_name || 'unknown';
  const language = item.json.language || 'en';
  const xmlText = item.json.xmlData || '';

  const parts = xmlText.split('<item>');
  const rssItems = [];
  for (let i = 1; i < parts.length; i++) {
    const endIdx = parts[i].indexOf('</item>');
    if (endIdx !== -1) rssItems.push(parts[i].substring(0, endIdx));
  }

  for (const block of rssItems.slice(0, 20)) {
    const title = getTagContent(block, 'title');
    let link = getTagContent(block, 'link');
    if (!link) link = getTagContent(block, 'guid');
    const description = getTagContent(block, 'description');
    const imageUrl = getImageUrl(block);

    if (!title || !link) continue;

    const hashInput = (title + link).toLowerCase().replace(/\s+/g, '');
    const content_hash = crypto.createHash('sha256').update(hashInput).digest('hex');

    rows.push({
      source_name,
      source_url: link,
      content_hash,
      raw_title: title.substring(0, 500),
      raw_body: description.substring(0, 5000),
      raw_image_url: imageUrl,
      language,
      status: 'pending'
    });
  }
}

return rows.map(r => ({ json: r }));

const items = $input.all();
return [{
  json: {
    message: 'Ingestion run complete',
    rows_processed: items.length,
    timestamp: new Date().toISOString()
  }
}];
